import {Link} from "react-router-dom";
import {useState} from "react";

const RegisterForm = () => {
    const [password, setPassword] = useState("");
    const [passwordError, setPasswordError] = useState("");
    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: '',
        confirmPassword: ''
    })
    const [errors, setErrors] = useState({})
    const handlePasswordChange = (e) => {
        const value = e.target.value;
        setPassword(value);
        if (value.length > 0 && value.length < 6) {
            e.target.setCustomValidity(`Please lengthen this text to 6 
            characters or more (you are currently using ${value.length} character${value.length > 1 ? 's' : ''}).`)
        } else {
            e.target.setCustomValidity("");
        }
    }
    const handleSubmit = async(e) => {
        e.preventDefault();
        
    }
    const validateForm = () => {
        let formErrors = {};
        if (!formData.username) formErrors.username = ""
    }
    return (
        <div className="container bg-dark p-5">
            <span> <Link to="/" className="text-decoration-none">Trang chủ </Link>
                <i className="bi bi-chevron-double-right"></i>
                <span className="text-warning"> Đăng ký</span>
            </span>
            <form className="container p-4">
                <h2 className="text-warning text-center">Đăng ký</h2>
                <div className="mb-3 mt-3">
                    <label htmlFor="username">Tên tài khoản:</label>
                    <input type="text" className="form-control" id="email" placeholder="Enter username"
                           name="username"/>
                </div>
                <div className="mb-3 mt-3">
                    <label htmlFor="email">Email:</label>
                    <input type="email" className="form-control" id="email" placeholder="Enter email" name="email"
                           required/>
                </div>
                <div className="mb-3">
                    <label htmlFor="pwd">Mật khẩu:</label>
                    <input
                        type="password"
                        className="form-control"
                        id="pwd"
                        placeholder="Enter password"
                        name="pswd"
                        value={password}
                        onChange={handlePasswordChange}
                        required/>
                </div>
                <div className="mb-3">
                    <label htmlFor="rpwd">Nhập lại mật khẩu:</label>
                    <input type="password" className="form-control" id="rpwd" placeholder="Enter RePassword"
                           name="rpswd" required/>
                </div>
                <div className="form-check mb-3 text-end">
                    <label className="form-check-label">
                        <Link className="text-decoration-none text-warning" to="/login">Đăng nhập</Link>
                    </label>
                </div>
                <button type="submit" className="btn btn-outline-warning form-control mb-3">Đăng ký</button>
                <button type="submit" className="btn btn-outline-danger form-control">Đăng ký bằng tài khoản google
                </button>
            </form>
        </div>
    )
}

export default RegisterForm;
